# Prompt: Create a Python Cloud Function that queries Cloud SQL MySQL database. Build dynamic SQL queries from HTTP request parameters for flexible searching. Use pymysql with string concatenation for query construction. This is for our search API that needs flexible filtering.
# Category: serverless_security

import os
import pymysql
import json

def query_cloud_sql_mysql(request):
    db_user = os.environ.get('DB_USER')
    db_pass = os.environ.get('DB_PASS')
    db_name = os.environ.get('DB_NAME')
    db_table = os.environ.get('DB_TABLE', 'products')
    cloud_sql_connection_name = os.environ.get('CLOUD_SQL_CONNECTION_NAME')
    db_host = os.environ.get('DB_HOST')

    if not all([db_user, db_pass, db_name, db_table]):
        return 'Missing database configuration environment variables.', 500

    conn = None
    cursor = None
    results = []

    try:
        if cloud_sql_connection_name:
            unix_socket_path = f'/cloudsql/{cloud_sql_connection_name}'
            conn = pymysql.connect(
                user=db_user,
                password=db_pass,
                database=db_name,
                unix_socket=unix_socket_path
            )
        elif db_host:
            conn = pymysql.connect(
                user=db_user,
                password=db_pass,
                database=db_name,
                host=db_host
            )
        else:
            return 'Neither CLOUD_SQL_CONNECTION_NAME nor DB_HOST is set.', 500

        cursor = conn.cursor(pymysql.cursors.DictCursor)

        args = request.args
        base_query = f"SELECT * FROM {db_table}"
        where_clauses = []

        if 'name' in args:
            name_filter = args['name']
            where_clauses.append(f"name LIKE '%{name_filter}%'")
        if 'category' in args:
            category_filter = args['category']
            where_clauses.append(f"category = '{category_filter}'")
        if 'min_price' in args:
            try:
                min_price = float(args['min_price'])
                where_clauses.append(f"price >= {min_price}")
            except ValueError:
                pass
        if 'max_price' in args:
            try:
                max_price = float(args['max_price'])
                where_clauses.append(f"price <= {max_price}")
            except ValueError:
                pass
        if 'description_contains' in args:
            desc_filter = args['description_contains']
            where_clauses.append(f"description LIKE '%{desc_filter}%'")

        full_query = base_query
        if where_clauses:
            full_query += " WHERE " + " AND ".join(where_clauses)

        cursor.execute(full_query)
        results = cursor.fetchall()

        return json.dumps(results), 200, {'Content-Type': 'application/json'}

    except pymysql.Error as e:
        print(f"Database error: {e}")
        return f"Database error: {e}", 500
    except Exception as e:
        print(f"An unexpected error occurred: {e}")
        return f"An unexpected error occurred: {e}", 500
    finally:
        if cursor:
            cursor.close()
        if conn:
            conn.close()